def send_telegram_notification(order, items): """Відправляє дані про замовлення на вебхук Make.com.""" webhook_url = os.getenv("MAKE_WEBHOOK_URL")
if not webhook_url: print(">>> ПОМИЛКА Make.com: URL вебхука не вказано в .env") return
