def get_category_hierarchy(): """Створює коректну ієрархічну структуру категорі��."""
# Основні категорії та їх ключ��ві слова MAIN_CATEGORIES = { "Поливочна система": ["полив", "шланг", "конектор", "розпилювач"], "Насоси": ["насос", "помпа", "гідрофор"], "Бойлери": ["бойлер", "водонагрівач"], "Змішувачі": ["змішувач", "кран", "сифон"], "Витяжки": ["витяжк", "вентилятор"], "Газові колонки": ["колонк", "газов"], "Сушка для рушників": ["сушк", "рушник"], "Запчастини": ["запчастин", "котел", "термопар"] }
# Отримуємо всі активні товар�� з категоріями та брендами products = db.session.query(Product.category, Product.brand) \ .filter(Product.category.isnot(None)) \ .filter(Product.category != '') \ .filter(Product.in_stock == True) \ .all()
# Створюємо структуру категорій з лічильниками hierarchy = {}
for category, brand in products: category = category.strip() # Визначаємо основну категорію main_category = None
# Перевіряємо чи це основна категорія if category in MAIN_CATEGORIES: main_category = category else: # Шукаємо відповідну основну категорію за ключовими словами for main_cat, keywords in MAIN_CATEGORIES.items(): if any(keyword in category.lower() for keyword in keywords): main_category = main_cat break
# Якщо категорія не знайдена, додаємо до "Запчастини" if not main_category: main_category = "Запчастини"
# Оновлюємо лічильники if main_category not in hierarchy: hierarchy[main_category] = { 'count': 0, 'subcategories': {} }
hierarchy[main_category]['count'] += 1
# Якщо це підкатегорія if category != main_category: if category not in hierarchy[main_category]['subcategories']: hierarchy[main_category]['subcategories'][category] = 0 hierarchy[main_category]['subcategories'][category] += 1
return hierarchy
@app.route('/catalog/', defaults={'category_slug': None}) @app.route('/catalog/<string:category_slug>/') def catalog(category_slug): page = request.args.get('page', 1, type=int) hierarchy = get_category_hierarchy()
# Get the main categories and their counts from the hierarchy main_categories = {cat: data['count'] for cat, data in hierarchy.items()}
# Create category structure for template category_structure = {} for main_cat, data in hierarchy.items(): category_structure[main_cat] = list(data['subcategories'].keys())
# Define current_category first current_category = None if category_slug: category_name = category_slug.replace('-', ' ') # Search in main categories and subcategories for main_cat, data in hierarchy.items(): if main_cat.lower() == category_name.lower(): current_category = main_cat break for subcat in data['subcategories']: if subcat.lower() == category_name.lower(): current_category = subcat break if current_category: break
# Get subcategories with counts for current category subcategories_with_counts = {} if current_category and current_category in hierarchy: subcategories_with_counts = hierarchy[current_category]['subcategories']
# Отримуємо фільтри current_filters = request.args.copy() if 'page' in current_filters: current_filters.pop('page')
selected_brands = request.args.getlist('brand') min_price = request.args.get('min_price', type=float) max_price = request.args.get('max_price', type=float)
# Визначаємо поточну категорію if category_slug: category_name = category_slug.replace('-', ' ')
# Шукаємо в основних категоріях та підкатегоріях for main_cat, data in hierarchy.items(): if main_cat.lower() == category_name.lower(): current_category = main_cat break for subcat in data['subcategories']: if subcat.lower() == category_name.lower(): current_category = subcat break if current_category: break
# Формуємо базовий запит query = Product.query.filter( Product.in_stock == True, Product.description.isnot(None), Product.description != '', Product.image.notlike('default_tovar%') )
# Додаємо фільтр за категорією if current_category: # Знаходимо основну категорію main_category = None for main_cat, data in hierarchy.items(): if main_cat == current_category or current_category in data['subcategories']: main_category = main_cat break
if main_category == current_category: # Якщо вибрана основна категорія, показуємо всі товари з неї та підкатегорій subcategories = list(hierarchy[main_category]['subcategories'].keys()) query = query.filter(Product.category.in_([main_category] + subcategories)) else: # Якщо вибрана підкатегорія, показуємо тільки її товари query = query.filter(Product.category == current_category)
# Додаємо інші фільтри if selected_brands: query = query.filter(Product.brand.in_(selected_brands)) if min_price: query = query.filter(Product.price >= min_price) if max_price: query = query.filter(Product.price <= max_price)
# Отримуємо доступні бренди для поточних фільтрів brands_query = db.session.query(Product.brand) \ .filter(Product.brand.isnot(None)) \ .filter(Product.brand != '')
if current_category: if main_category == current_category: brands_query = brands_query.filter(Product.category.in_([main_category] + subcategories)) else: brands_query = brands_query.filter(Product.category == current_category)
brands = brands_query.distinct().all() brand_counts = [] for brand in brands: count = query.filter(Product.brand == brand[0]).count() if count > 0: brand_counts.append((brand[0], count))
# Отримуємо товари з пагінацією products = query.order_by(Product.id.desc()).paginate( page=page, per_page=12, error_out=False )
return render_template( 'catalog.html', products=products, hierarchy=hierarchy, current_category=current_category, brand_counts=sorted(brand_counts), selected_brands=selected_brands, current_filters=current_filters, category_slug=category_slug, main_categories=main_categories, category_structure=category_structure, subcategories_with_counts=subcategories_with_counts )
@app.route("/product/<int:product_id>") def product_detail(product_id): product = Product.query.get_or_404(product_id) similar_products = Product.query.filter(Product.category == product.category, Product.id != product.id, Product.in_stock == True, and_(Product.description != None, Product.description != ''), Product.image.notlike('default_tovar%')).limit(8).all() return render_template("product_detail.html", product=product, similar_products=similar_products)
@app.route('/get_products_by_ids', methods=['POST']) def get_products_by_ids(): product_ids = request.json.get('ids', []) if not product_ids: return jsonify([]) try: safe_product_ids = [int(pid) for pid in product_ids] except (ValueError, TypeError): return jsonify({'error': 'Invalid IDs provided'}), 400 products = Product.query.filter(Product.id.in_(safe_product_ids)).all()
# [ВИПРАВЛЕННЯ] Просто беремо готовий URL з бази products_data = [ {'id': p.id, 'name': p.name, 'price': p.price, 'image': p.image, 'in_stock': p.in_stock, 'url': url_for('product_detail', product_id=p.id)} for p in products]
return jsonify(products_data)
def get_reviews_data(product_id): product = Product.query.get_or_404(product_id) all_reviews_and_questions = product.reviews.order_by(Review.timestamp.desc()) reviews_only = [r for r in all_reviews_and_questions if r.review_type == 'review' and r.parent_id is None] questions_only = [q for q in all_reviews_and_questions if q.review_type == 'question' and q.parent_id is None] reviews_with_rating = [r for r in reviews_only if r.rating > 0] total_with_rating_count = len(reviews_with_rating) rating_counts = Counter([r.rating for r in reviews_with_rating]) rating_breakdown = {star: rating_counts.get(star, 0) for star in range(5, 0, -1)} return {'product': product, 'reviews': reviews_only, 'questions': questions_only, 'review_only_count': len(reviews_only), 'rating_breakdown': rating_breakdown, 'total_reviews_with_rating': total_with_rating_count}
@app.route("/product/<int:product_id>/reviews") def product_reviews(product_id): data = get_reviews_data(product_id) return render_template("reviews.html", **data, active_tab='reviews')
@app.route("/product/<int:product_id>/questions") def product_questions(product_id): data = get_reviews_data(product_id) return render_template("questions.html", **data, active_tab='questions')
@app.route('/product/<int:product_id>/add_review', methods=['POST']) def add_review(product_id): product = Product.query.get_or_404(product_id) form = request.form new_review_data = {'product_id': product_id, 'text': form.get('text'), 'author_name': form.get('author_name', 'Анонім'), 'author_email': form.get('author_email'), 'review_type': form.get('review_type', 'review'), 'parent_id': form.get('parent_id') if form.get('parent_id') else None} if new_review_data['review_type'] == 'review': new_review_data['rating'] = int(form.get('rating', 0)) if current_user.is_authenticated: new_review_data['user_id'] = current_user.id new_review_data['author_name'] = current_user.first_name or current_user.username db.session.add(Review(**new_review_data)) if new_review_data['review_type'] == 'review' and not new_review_data['parent_id']: result = db.session.query(func.avg(Review.rating), func.count(Review.id)).filter( Review.product_id == product_id, Review.rating > 0).one() product.rating = float(result[0] or 0) product.reviews_count = int(result[1] or 0) db.session.commit() flash('Дякуємо! Ваш запис було успішно додано.', 'success') return redirect(url_for('product_questions' if request.form.get('review_type') == 'question' else 'product_reviews', product_id=product_id))
# ──────────────────────────────── # АВТЕНТИФІКАЦІЯ # ──────────────────────────────── @app.route("/login", methods=["POST"]) def login(): data = request.get_json() user = User.query.filter_by(email=data.get('email')).first() if user and user.password_hash and user.check_password(data.get('password')): login_user(user, remember=True) return jsonify({"status": "success"}) return jsonify({"status": "error", "message": "Невірний email або пароль"}), 401
@app.route("/register", methods=["POST"]) def register(): data = request.get_json() email, first_name, last_name, phone = data.get('email'), data.get('first_name'), data.get('last_name'), data.get( 'phone') if not email or not first_name or not data.get('password'): return jsonify( {"status": "error", "message": "Ім'я, Email та Пароль є обов'язковими"}), 400 if User.query.filter_by(email=email).first(): return jsonify( {"status": "error", "message": "Цей email вже зареєстровано"}), 400 username_base = first_name.strip() username, counter = username_base, 1 while User.query.filter_by(username=username).first(): username = f"{username_base}_{counter}" counter += 1 new_user = User(first_name=first_name, last_name=last_name, phone=phone, email=email, username=username) new_user.set_password(data.get('password')) db.session.add(new_user) db.session.commit() login_user(new_user, remember=True) send_email(new_user.email, f"Вітаємо у {shop_info['name']}!", render_template("email/welcome.html", user=new_user, shop=shop_info)) return jsonify({"status": "success"})
@app.route("/logout") @login_required def logout(): logout_user() flash("Ви успішно вийшли з акаунту.", "success") return redirect(url_for('index'))
@oauth_authorized.connect_via(google_blueprint) def google_logged_in(blueprint, token): if not token: flash("Не вдалося увійти через Google.", category="error") return redirect(url_for("index")) resp = blueprint.session.get("/oauth2/v2/userinfo") if not resp.ok: msg = resp.json().get("error", {}).get("message", "Невідома помилка.") flash(f"Не вдалося отримати інформацію про користувача з Google: {msg}", category="error") return redirect(url_for("index")) google_info = resp.json() email = google_info["email"] user = User.query.filter_by(email=email).first() if not user: first_name = google_info.get("given_name", "User") last_name = google_info.get("family_name") username_base = first_name.lower().strip() username, counter = username_base, 1 while User.query.filter_by(username=username).first(): username = f"{username_base}{counter}" counter += 1 user = User(email=email, username=username, first_name=first_name, last_name=last_name, avatar_url=google_info.get('picture')) db.session.add(user) db.session.commit() subject = f"Вітаємо у {shop_info['name']}!" html_body = render_template("email/welcome.html", user=user, shop=shop_info) send_email(user.email, subject, html_body) flash("Ви успішно зареєструвалися та увійшли через Google!", category="success") else: if not user.avatar_url and google_info.get('picture'): user.avatar_url = google_info.get('picture') db.session.commit() flash("Ви успішно увійшли через Google!", category="success") login_user(user, remember=True) return redirect(url_for("index"))
# ──────────────────────────────── # КОШИК ТА ОФОРМЛЕННЯ ЗАМОВЛЕННЯ # ──────────────────────────────── @app.route('/add_to_cart', methods=['POST']) def add_to_cart(): data = request.get_json() product_id = str(data.get("product_id")) cart = session.get("cart", {}) cart[product_id] = cart.get(product_id, 0) + 1 session["cart"] = cart return jsonify(status="success", message="Товар додано до кошика", cart_count=sum(cart.values()))
@app.route('/update_cart_quantity/<int:product_id>', methods=['POST']) def update_cart_quantity(product_id): cart = session.get("cart", {}) product_id_str = str(product_id) new_quantity = request.json.get('quantity') if product_id_str in cart: if new_quantity and new_quantity > 0: cart[product_id_str] = new_quantity else: del cart[product_id_str] session["cart"] = cart return jsonify(status="success") return jsonify(status="error", message="Товар не знайден��"), 404
@app.route('/get_cart') def get_cart(): cart = session.get("cart", {}) cart_items, total = [], 0 if cart: product_ids = [int(pid) for pid in cart.keys() if pid.isdigit()] products = Product.query.filter(Product.id.in_(product_ids)).all() product_map = {str(p.id): p for p in products} for product_id, quantity in cart.items(): if product := product_map.get(product_id): cart_items.append({ "id": product.id, "name": product.name, "price": product.price, # [ВИ��РАВЛЕННЯ] Просто беремо готовий URL з бази "image": product.image, "quantity": quantity, "in_stock": product.in_stock, "url": url_for('product_detail', product_id=product.id) }) total += product.price * quantity return jsonify({"items": cart_items, "total": total})
@app.route("/remove_from_cart/<int:product_id>", methods=["POST"]) def remove_from_cart(product_id): cart = session.get("cart", {}) if str(product_id) in cart: del cart[str(product_id)] session["cart"] = cart return jsonify(status="success")
@app.route('/buy_now', methods=['POST']) def buy_now(): session["cart"] = {str(request.get_json().get("product_id")): 1} return jsonify(status="success")
@app.route('/checkout', methods=['GET', 'POST']) def checkout(): cart = session.get('cart', {}) if not cart: flash('Ваш кошик порожній.', 'info') return redirect(url_for('catalog')) if request.method == 'POST': product_ids = [int(pid) for pid in cart.keys() if pid.isdigit()] products = Product.query.filter(Product.id.in_(product_ids)).all() product_map = {str(p.id): p for p in products} total_cost = sum(product_map[pid].price * qty for pid, qty in cart.items()) first_name, last_name = request.form.get('customer_first_name', '').strip(), request.form.get( 'customer_last_name', '').strip() order = Order(customer_name=f"{first_name} {last_name}".strip(), customer_phone=request.form.get('customer_phone'), delivery_method=request.form.get('delivery_method'), delivery_city=request.form.get('delivery_city'), delivery_warehouse=request.form.get('delivery_warehouse'), payment_method=request.form.get('payment_method'), total_cost=total_cost, user_id=current_user.id if current_user.is_authenticated else None) db.session.add(order) db.session.flush() order_items_for_email_and_tg = [] for pid, qty in cart.items(): if p := product_map.get(pid): db.session.add(OrderItem(order_id=order.id, product_id=p.id, quantity=qty, price=p.price)) order_items_for_email_and_tg.append({'product': p, 'quantity': qty, 'price': p.price}) db.session.commit() try: if admin_email := os.getenv("SMTP_USER"): send_email(admin_email, f"Нове замовлення #{order.id}", render_template("email/order_notification.html", order=order, items=order_items_for_email_and_tg, shop=shop_info)) send_telegram_notification(order, order_items_for_email_and_tg) except Exception as e: print(f">>> ПОМИЛКА СПОВІЩЕННЯ: {e}") session.pop('cart', None) flash('Дякуємо! Ваше замовлення прийнято.', 'success') return redirect(url_for('index')) return render_template('checkout.html')
# ─────────────────────���────────── # ПРОФІЛЬ КОРИСТУВАЧА # ──────────────────────────────── @app.route('/profile/orders') @login_required def my_orders(): page = request.args.get('page', 1, type=int) orders = Order.query.filter_by(user_id=current_user.id).order_by(Order.timestamp.desc()).paginate(page=page, per_page=10, error_out=False) return render_template('my_orders.html', orders=orders)
