new_email = request.form.get('email') if new_email != current_user.email: if User.query.filter_by(email=new_email).first(): flash('Цей email вже використовується іншим користувачем.', 'danger') return redirect(url_for('profile_settings')) current_user.email = new_email
db.session.commit() flash('Ваші дані успішно оновлено.', 'success')
elif 'change_password' in request.form: current_password = request.form.get('current_password') new_password = request.form.get('new_password') confirm_password = request.form.get('confirm_password')
if not current_user.password_hash: flash('Неможливо змінити пароль, оскільки ви увійшли через соціальну мережу.', 'warning') elif not current_user.check_password(current_password): flash('Невірний поточний пароль.', 'danger') elif not new_password or len(new_password) < 6: flash('Новий пароль має бути не менше 6 символів.', 'danger') elif new_password != confirm_password: flash('Паролі не співпадають.', 'danger') else: current_user.set_password(new_password) db.session.commit() flash('Пароль успішно змінено.', 'success')
return redirect(url_for('profile_settings'))
return render_template('profile_settings.html')
# ──────────────────────────────── # АДМІН-ПАНЕЛЬ # ──────────────────────────────── @app.route('/admin/orders', methods=['GET', 'POST']) @login_required @admin_required def admin_orders(): if request.method == 'POST': order_id, new_status = request.form.get('order_id'), request.form.get('status') if order := Order.query.get(order_id): order.status = new_status db.session.commit() flash(f"Статус замовлення #{order.id} оновлено.", "success") return redirect(url_for('admin_orders', status=request.args.get('status', 'Нове'))) page = request.args.get('page', 1, type=int) status_filter = request.args.get('status', 'Нове') query = Order.query if status_filter == 'all' else Order.query.filter_by(status=status_filter) orders = query.order_by(Order.timestamp.desc()).paginate(page=page, per_page=15, error_out=False) all_statuses = ['Нове', 'Відправлено', 'Виконано', 'Скасовано'] return render_template('admin_orders.html', orders=orders, all_statuses=all_statuses, current_status=status_filter)
