@app.route("/admin/add_product", methods=['GET', 'POST']) @login_required @admin_required def add_product(): if request.method == 'POST': new_product = Product( name=request.form['name'], price=float(request.form['price']), description=request.form['description'], # [ВИПРАВЛЕНО] Зберігаємо тільки ім'я файлу image=request.form['image'].strip() or 'default_tovar.png', category=request.form['category'], in_stock='in_stock' in request.form ) db.session.add(new_product) db.session.commit() flash(f"Товар '{new_product.name}' додано!", "success") return redirect(url_for('catalog')) return render_template("add_product.html")
@app.route("/admin/edit_product/<int:product_id>", methods=['GET', 'POST']) @login_required @admin_required def edit_product(product_id): product = Product.query.get_or_404(product_id) if request.method == 'POST': product.name = request.form['name'] product.price = float(request.form['price']) product.description = request.form['description'] # [ВИПРАВЛЕНО] Зберігаємо тільки ім'я файлу product.image = request.form['image'].strip() or 'default_tovar.png' product.category = request.form['category'] product.in_stock = 'in_stock' in request.form
db.session.commit() flash(f"Товар '{product.name}' оновлено!", "success") return redirect(url_for('catalog'))
