@app.route("/admin/delete_product/<int:product_id>", methods=["POST"]) @login_required @admin_required def delete_product(product_id): product = Product.query.get_or_404(product_id) db.session.delete(product); db.session.commit() flash(f"Товар '{product.name}' видалено.", "success") return redirect(url_for('catalog'))
@app.route('/admin/unfinished') @login_required @admin_required def admin_unfinished(): page = request.args.get('page', 1, type=int) query = Product.query active_filters = [k for k in request.args if k in ['no_stock', 'no_description', 'no_image']] if not active_filters: query = query.filter( db_or(Product.in_stock == False, (Product.description == None) | (Product.description == ''), Product.image.like('default_tovar%') | (Product.image == None))) else: if 'no_stock' in active_filters: query = query.filter(Product.in_stock == False) if 'no_description' in active_filters: query = query.filter( (Product.description == None) | (Product.description == '')) if 'no_image' in active_filters: query = query.filter( Product.image.like('default_tovar%') | (Product.image == None))
counts = {'no_stock': Product.query.filter(Product.in_stock == False).count(), 'no_description': Product.query.filter( (Product.description == None) | (Product.description == '')).count(), 'no_image': Product.query.filter(Product.image.like('default_tovar%') | (Product.image == None)).count()}
products = query.order_by(Product.id.desc()).paginate(page=page, per_page=20, error_out=False) return render_template('admin_unfinished.html', products=products, counts=counts)
# ──────────────────────────────── # ІНШІ МАРШРУТИ ТА API # ──────────────────────────────── @app.route("/send_message", methods=["POST"]) def send_message(): form = request.form form_data = {'name': form.get('name'), 'email': form.get('email'), 'message': form.get('message')} subject = f"Нове повідомлення з сайту від {form_data['name']}" html_body = render_template('email/contact_form_notification.html', data=form_data, shop=shop_info) if send_email(os.getenv("SMTP_USER"), subject, html_body): return jsonify(status="success", message="✅ Повідомлення успішно надіслано!") else: return jsonify(status="error", message="❌ Помилка сервера при відправці повідомлення."), 500
# ──────────────────────────────── # API ДЛЯ ІНТЕГРАЦІЇ З BAS (1C) - НАДІЙНА ВЕРСІЯ # ───────────────────���───────────
def require_api_key(f): @wraps(f) def decorated_function(*args, **kwargs): api_key = os.getenv('BAS_API_KEY') provided_key = request.headers.get('X-API-KEY') or request.args.get('key') if not api_key or provided_key != api_key: return "failure\nInvalid API key.", 401 return f(*args, **kwargs)
return decorated_function
@app.route('/cabinet/product_import/get_1c_system_info', methods=['GET']) def handle_bas_handshake(): print("BAS: пройдено етап handshake.") return "success\nphpsessid\n1234567\nzip=no\nfile_limit=20971520"
def _get_cloudinary_url(image_filename): """ Внутрішня функція для генерації повного URL зображення з Cloudinary. Використовується тільки всередині app.py під час імпорту. """ # ID для зображення за замовчуванням (заглушки) DEFAULT_IMAGE_PUBLIC_ID = "default_tovar_dw8qbz"
public_id = "" try: if image_filename and image_filename.strip(): # Логіка для реальних товарів filename_without_extension = os.path.splitext(image_filename)[0] public_id = f"products/products/{filename_without_extension}" else: # Логіка для товарів без картинки public_id = DEFAULT_IMAGE_PUBLIC_ID
# Генеруємо URL url, _ = cloudinary.utils.cloudinary_url( public_id, secure=True, fetch_format="auto", quality="auto" ) return url except Exception as e: # Якщо сталася помилка, виводимо її в лог print(f"!!! ПОМИЛКА генерації Cloudinary URL для ID '{public_id}': {e}") # Повертаємо None, щоб в базу не записалося нічого або помилкове значення return None
@app.route('/api/bas_import', methods=['POST'], strict_slashes=False) @require_api_key def bas_import(): if 'file' not in request.files: return "failure\nFile part is missing in the request.", 400 cml_file = request.files['file'] if cml_file.filename == '': return "failure\nNo selected file.", 400
print(f"BAS: Отримано файл '{cml_file.filename}'. Починаю обробку з lxml...")
try: raw_data = cml_file.read() try: parser_utf8 = lxml_etree.XMLParser(recover=True, encoding='utf-8') root = lxml_etree.fromstring(raw_data, parser=parser_utf8) print("Info: Файл успішно розібрано з кодуванням UTF-8.") except Exception: parser_win1251 = lxml_etree.XMLParser(recover=True, encoding='windows-1251') root = lxml_etree.fromstring(raw_data, parser=parser_win1251) print("Info: Файл успішно розібрано з кодуванням windows-1251.")
for elem in root.getiterator(): if '}' in elem.tag: elem.tag = elem.tag.split('}', 1)[1]
catalog_node = root.find('.//Каталог') if catalog_node is None: return "failure\nНе знайдено тег <Каталог>.", 400
groups = {g.findtext('Ид'): g.findtext('Наименование') for g in root.findall('.//Группа')} products_from_xml = catalog_node.findall('.//Товар') print(f"В XML знайдено {len(products_from_xml)} товарів. Починаю обробку...")
# ================================================================ # [ОПТИМІЗАЦІЯ №1]: Отримуємо всі існуючі товари з бази ОДНИМ ЗАПИТОМ # ================================================================ print("Оптимізація: Завантажую ��снуючі товари з бази даних...") # Завантажуємо тільки ID та назву для економії пам'яті existing_products_raw = db.session.query(Product.id, Product.name).all() # Створюємо словник для миттєвого пошуку: { 'Назва товару': id } existing_products_map = {name: pid for pid, name in existing_products_raw} print(f"Завантажено {len(existing_products_map)} існуючих товарів.")
# ================================================================ # [ОПТИМІЗАЦІЯ №2]: Готуємо списки для пакетної обробки # ================================================================ products_to_update = [] products_to_add = [] default_image_url = _get_cloudinary_url(None)
# Починаємо цикл обробки XML, але НЕ робимо запитів до бази всередині for product_node in products_from_xml: product_id_from_xml = product_node.findtext('Ид') if not product_id_from_xml: continue
# --- Ця логіка збору даних з XML залишається без змін --- name = (product_node.findtext('Наименование') or 'Без назви').strip() description = (product_node.findtext('Описание') or '').strip() group_id_node = product_node.find('.//Групи/Ид') group_id = group_id_node.text if group_id_node is not None else None category = groups.get(group_id, "Загальна") image_filename_from_xml = (product_node.findtext('Картинка') or '').strip() final_image_url = _get_cloudinary_url(image_filename_from_xml) if not final_image_url: final_image_url = default_image_url
price = 0.0 in_stock = False offer_node = root.find(f".//Предложение[Ид='{product_id_from_xml}']") if offer_node is not None: price_node = offer_node.find('.//ЦенаЗаЕдиницу') if price_node is not None and price_node.text: try: price = float(re.match(r"[\d.]+", price_node.text.replace(',', '.')).group(0)) except (ValueError, AttributeError): pass quantity_node = offer_node.find('Количество') if quantity_node is not None and quantity_node.text: try: if int(float(quantity_node.text.strip())) > 0: in_stock = True except (ValueError, TypeError): pass
if not in_stock: stock_prop_node = product_node.find(".//ЗначенняРеквизита[Наименование='Наличие']/Значення") if stock_prop_node is not None and stock_prop_node.text and stock_prop_node.text.strip().lower() in [ 'true', 'да', 'є', 'yes']: in_stock = True else: stock_prop_node_alt = product_node.find(".//ЗначенняСвойства[Ид='ИД-Наличие']/Значення") if stock_prop_node_alt is not None and stock_prop_node_alt.text and stock_prop_node_alt.text.lower() == 'true': in_stock = True
# --- Логіка визначення бренду також без змін --- brand = None if description: clean_description = description.replace('<br>', '\n').replace('<BR>', '\n') brand_keywords = ['виробник:', 'бренд:', 'виробництво:', 'торгова марка:'] known_brands = [ 'Ariston', 'Aquapulse', 'Atlantic', 'Gorenje', 'Eldom', 'Forwater', 'Frap', 'Immergas', 'Itap', 'KRAZ', 'Lidz', 'Modus', 'Novatec', 'Optima', 'Oasis', 'Pedrollo', 'Pentax', 'Purflux', 'Q-tap', 'Rudis', 'Santehplast', 'Sprut', 'Aquatica', 'Thermo Alliance', 'Vents', 'Vital', 'Wilo', 'Zanussi', 'Zegor', 'Aqua', 'Арма', 'Донтерм', 'Прометей', 'Насоси плюс обладнання', 'Опалення', 'Gerts' ] for keyword in brand_keywords: if keyword in clean_description.lower(): start_index = clean_description.lower().find(keyword) + len(keyword) brand_candidate = clean_description[start_index:].strip().split('\n')[0].strip() if brand_candidate: brand = brand_candidate break if not brand: for known_brand in sorted(known_brands, key=len, reverse=True): if re.search(r'\b' + re.escape(known_brand) + r'\b', clean_description, re.IGNORECASE): brand = known_brand break if brand: # Спочатку видаляємо HTML-теги, потім замінюємо &nbsp; на звичайний пробіл, # а потім прибираємо зайві пробіли на початку та в кінці. brand = re.sub(r'<[^>]+>', '', brand).replace('&nbsp;', ' ').strip() if brand: # Перевіряємо, чи щось залишилось після очищення brand = brand[:100] # Обрізаємо до 100 символів else: brand = None # Якщо нічого не залишилось, ставимо None
# Створюємо словник з даними товару product_data = { 'name': name, 'price': price, 'description': description, 'category': category, 'brand': brand, 'image': final_image_url, 'in_stock': in_stock }
# Розподіляємо товар у відповідний список: на оновлення або на додавання if name in existing_products_map: product_data['id'] = existing_products_map[name] # Додаємо ID для оновлення products_to_update.append(product_data) else: products_to_add.append(product_data)
updated_count = len(products_to_update) added_count = len(products_to_add) print(f"Завершення циклу. Підготовлено до оновлення: {updated_count}, до додавання: {added_count}.")
# ================================================================ # [ОПТИМІЗАЦІЯ №3]: Виконуємо пакетні операції з базою # ================================================================ if products_to_add: print("Виконую пакетне додавання нових товарів...") db.session.bulk_insert_mappings(Product, products_to_add) print("Пакетне додавання завершено.")
if products_to_update: print("Виконую пакетне оновлення існуючих товарів...") db.session.bulk_update_mappings(Product, products_to_update) print("Пакетне оновлення завершено.")
# Робимо commit тільки якщо були якісь зміни if products_to_add or products_to_update: print("Зберігаю зміни в базі даних (commit)...") db.session.commit() print("Зміни успішно збережено.") else: print("Немає товарів для додавання або оновлення.")
message = f"Імпорт CommerceML успішно завершено. Оновлено: {updated_count}, Додано нових: {added_count}." print(message) return "success"
except Exception as e: db.session.rollback() import traceback error_details = traceback.format_exc() print(f"КРИТИЧНА ПОМИЛКА під час обробки файлу: {e}\n{error_details}") return f"failure\nВнутрішня помилка сервера: {e}", 500
# ... (ваш код після функції)
def require_bot_api_key(f): @wraps(f) def decorated_function(*args, **kwargs): api_key = os.getenv('BOT_API_KEY') provided_key = request.headers.get('X-Bot-API-Key') if not api_key or provided_key != api_key: return jsonify( {"status": "error", "message": "Invalid API key"}), 401 return f(*args, **kwargs)
return decorated_function
@app.route('/api/order/<int:order_id>/update_status', methods=['POST']) @require_bot_api_key def api_update_order_status(order_id): order = Order.query.get_or_404(order_id) new_status = request.json.get('status') if new_status in ['Виконано', 'Скасовано', 'Нове', 'Відправлено']: order.status = new_status db.session.commit() return jsonify({"status": "success", "message": f"Order #{order.id} status updated to {new_status}"}) return jsonify({"status": "error", "message": "Invalid status"}), 400
@app.route('/api/orders') @require_bot_api_key def api_get_orders(): status = request.args.get('status') if not status: return jsonify({"status": "error", "message": "Status parameter is required"}), 400 orders = Order.query.filter_by(status=status).order_by(Order.timestamp.desc()).limit(10).all() orders_data = [ {"id": o.id, "date": o.timestamp.strftime('%Y-%m-%d'), "name": o.customer_name, "total": o.total_cost} for o in orders] return jsonify({"status": "success", "orders": orders_data})
# API ДЛЯ ІНТЕГРАЦІЇ З "НОВОЮ ПОШТОЮ" @app.route('/api/np/cities') def find_np_cities(): """Пошук населених пунктів.""" api_key = os.getenv('NOVA_POSHTA_API_KEY') query = request.args.get('q', '')
if not api_key: return jsonify({"error": "API-ключ Нової Пошти не налаштовано на сервері."}), 500 if len(query) < 2: return jsonify([])
payload = { "apiKey": api_key, "modelName": "Address", "calledMethod": "searchSettlements", "methodProperties": {"CityName": query, "Limit": "20"} } try: response = requests.post("https://api.novaposhta.ua/v2.0/json/", json=payload, timeout=5) response.raise_for_status() data = response.json() if data['success'] and data['data'][0]['TotalCount'] > 0: cities = data['data'][0]['Addresses'] return jsonify([{'ref': c['Ref'], 'name': c['Present']} for c in cities]) return jsonify([]) except requests.exceptions.RequestException as e: print(f"Помилка API Нової Пошти (міста): {e}") return jsonify({"error": "Помилка зв'язку з сервером Нової Пошти."}), 503
@app.route('/api/np/warehouses') def get_np_warehouses(): """Отримання ТІЛЬКИ ВІДДІЛЕНЬ для населеного пу��кту.""" api_key = os.getenv('NOVA_POSHTA_API_KEY') city_ref = request.args.get('city_ref', '')
if not api_key: return jsonify({"error": "API-ключ Нової Пошти не налаштовано на сервері."}), 500 if not city_ref: return jsonify([])
payload = { "apiKey": api_key, "modelName": "AddressGeneral", "calledMethod": "getWarehouses", "methodProperties": {"SettlementRef": city_ref} } try: response = requests.post("https://api.novaposhta.ua/v2.0/json/", json=payload, timeout=5) response.raise_for_status() data = response.json() if data['success']: all_warehouses = data.get('data', []) filtered_warehouses = [ w['Description'] for w in all_warehouses if w['Description'].startswith('Відділення') ] return jsonify(filtered_warehouses) return jsonify([]) except requests.exceptions.RequestException as e: print(f"Помилка API Нової Пошти (відділення): {e}") return jsonify({"error": "Помилка зв'язку з сервером Нової Пошти."}), 503
@app.errorhandler(404) def page_not_found(e): return render_template('404.html', shop=shop_info), 404
