def send_telegram_notification(order, items): """Відправляє дані про замовлення на вебхук Make.com.""" webhook_url = os.getenv("MAKE_WEBHOOK_URL")
if not webhook_url: print(">>> ПОМИЛКА Make.com: URL вебхука не вказано в .env") return
product_names = ", ".join([f"{item['product'].name} ({item['quantity']} шт)" for item in items])
delivery_details = order.delivery_method if order.delivery_method == 'Нова Пошта': delivery_details += f" ({order.delivery_city}, {order.delivery_warehouse})"
payload = { "order_id": order.id, "order_status": order.status, "customer_name": order.customer_name, "customer_phone": order.customer_phone, "product_name": product_names, "delivery_method": delivery_details, "payment_method": order.payment_method, "total_cost": f"{order.total_cost:.2f} ₴" }
try: response = requests.post(webhook_url, json=payload, timeout=10) if response.status_code == 200 and "Accepted" in response.text: print(f">>> Make.com: Дані про замовлення #{order.id} успішно надіслано!") else: print(f">>> Make.com: Помилка відповіді від сервера - {response.status_code} {response.text}") except requests.exceptions.RequestException as e: print(f">>> Make.com: КРИТИЧНА ПОМИЛКА при відправці сповіщення: {e}")
