class Product(db.Model): id = db.Column(db.Integer, primary_key=True) name = db.Column(db.String(100), nullable=False) price = db.Column(db.Float, nullable=False) description = db.Column(db.Text) image = db.Column(db.String(255), nullable=True) category = db.Column(db.String(100)) brand = db.Column(db.String(100), index=True, nullable=True) in_stock = db.Column(db.Boolean, default=True) rating = db.Column(db.Float, default=0.0) reviews_count = db.Column(db.Integer, default=0) reviews = db.relationship('Review', backref='product', lazy='dynamic', cascade="all, delete-orphan")
class Review(db.Model): id = db.Column(db.Integer, primary_key=True) rating = db.Column(db.Integer, nullable=False, default=0) text = db.Column(db.Text, nullable=True) timestamp = db.Column(db.DateTime, index=True, default=datetime.utcnow) user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True) author_name = db.Column(db.String(100), nullable=True) author_email = db.Column(db.String(120), nullable=True) product_id = db.Column(db.Integer, db.ForeignKey('product.id'), nullable=False) review_type = db.Column(db.String(50), nullable=False, default='review') parent_id = db.Column(db.Integer, db.ForeignKey('review.id'), nullable=True) replies = db.relationship('Review', backref=db.backref('parent', remote_side=[id]), lazy='dynamic', cascade="all, delete-orphan", order_by='Review.timestamp.asc()')
class Order(db.Model): id = db.Column(db.Integer, primary_key=True) status = db.Column(db.String(50), nullable=False, default='Нове') user_id = db.Column(db.Integer, db.ForeignKey('user.id'), nullable=True) customer_name = db.Column(db.String(100), nullable=False) customer_phone = db.Column(db.String(20), nullable=False) delivery_method = db.Column(db.String(50)) delivery_city = db.Column(db.String(100), nullable=True) delivery_warehouse = db.Column(db.String(255), nullable=True) payment_method = db.Column(db.String(50)) total_cost = db.Column(db.Float, nullable=False) timestamp = db.Column(db.DateTime, index=True, default=datetime.utcnow) items = db.relationship('OrderItem', backref='order', lazy='dynamic', cascade="all, delete-orphan")
class OrderItem(db.Model): id = db.Column(db.Integer, primary_key=True) order_id = db.Column(db.Integer, db.ForeignKey('order.id'), nullable=False) product_id = db.Column(db.Integer, db.ForeignKey('product.id'), nullable=False) quantity = db.Column(db.Integer, nullable=False) price = db.Column(db.Float, nullable=False) product = db.relationship('Product')
class OAuth(db.Model): id = db.Column(db.Integer, primary_key=True) provider = db.Column(db.String(50), nullable=False) created_at = db.Column(db.DateTime, default=datetime.utcnow, nullable=False) token = db.Column(db.JSON, nullable=False) user_id = db.Column(db.Integer, db.ForeignKey(User.id), nullable=False) user = db.relationship(User)
