counts = {'no_stock': Product.query.filter(Product.in_stock == False).count(), 'no_description': Product.query.filter( (Product.description == None) | (Product.description == '')).count(), 'no_image': Product.query.filter(Product.image.like('default_tovar%') | (Product.image == None)).count()}
products = query.order_by(Product.id.desc()).paginate(page=page, per_page=20, error_out=False) return render_template('admin_unfinished.html', products=products, counts=counts)
