// ===================================================================
//  ДОДАТКОВІ ФУНКЦІЇ
// ===================================================================
function initAutoApplyFilters() {
    const filtersForm = document.getElementById('auto-filters-form');
    if (!filtersForm) return;

    // Функція-затримувач, щоб не відправляти запит на кожне натискання клавіші
    const debounce = (func, delay) => {
        let timeout;
        return function(...args) {
            clearTimeout(timeout);
            timeout = setTimeout(() => func.apply(this, args), delay);
        };
    };

    const submitForm = () => {
        filtersForm.submit();
    };

    // Обробник для полів ціни з затримкою
    const debouncedSubmit = debounce(submitForm, 800);

    filtersForm.addEventListener('change', (e) => {
        // Застосовуємо відразу для чекбоксів
        if (e.target.type === 'checkbox') {
            submitForm();
        }
    });

    filtersForm.addEventListener('keyup', (e) => {
        // Застосовуємо з затримкою для полів вводу (ціна)
        if (e.target.type === 'number') {
            debouncedSubmit();
        }
    });
}

function initShowMoreFilters() {
    document.querySelectorAll('.filter-options-list[data-show-limit]').forEach(list => {
        const showLimit = parseInt(list.dataset.showLimit);
        const items = list.children;

        if (items.length <= showLimit) return;

        // Приховуємо елементи після ліміту
        for (let i = showLimit; i < items.length; i++) {
            items[i].style.display = 'none';
        }

        // Додаємо кнопку "Показати ще"
        const showMoreBtn = document.createElement('button');
        showMoreBtn.className = 'show-more-filters-btn';
        showMoreBtn.textContent = 'Показати ще';
        list.after(showMoreBtn);

        showMoreBtn.addEventListener('click', function() {
            const isExpanded = this.classList.contains('expanded');

            if (!isExpanded) {
                // Показуємо всі елементи
                for (let i = showLimit; i < items.length; i++) {
                    items[i].style.display = '';
                }
                this.textContent = 'Згорнути';
            } else {
                // Приховуємо елементи після ліміту
                for (let i = showLimit; i < items.length; i++) {
                    items[i].style.display = 'none';
                }
                this.textContent = 'Показати ще';
            }

            this.classList.toggle('expanded');
        });
    });
}

