{% extends "base.html" %}
{% block title %}{{ current_category or 'Каталог товарів' }}{% endblock %}

{% block content %}
<div class="container catalog-page">
    <div class="breadcrumbs">
        <a href="{{ url_for('index') }}">Головна</a> /
        <a href="{{ url_for('catalog') }}">Каталог</a>
        {% if current_category %}/ <span>{{ current_category }}</span>{% endif %}
    </div>

    <div class="catalog-content">
        <aside class="filters-sidebar sticky-sidebar">
            <form id="filters-form" method="GET" action="{{ url_for('catalog', category_slug=category_slug) }}">
                <!-- Приховані поля для існуючих фільтрів по брендах -->
                {% for brand in selected_brands %}
                <input type="hidden" name="brand" value="{{ brand }}">
                {% endfor %}

                <!-- ФІЛЬТР КАТЕГОРІЙ -->
                <div class="filter-group">
                    <h4 class="filter-title always-open">Категорії</h4>
                    <div class="radio-style-list">
                        {# Посилання "Всі категорії" #}
                        {% set all_cat_params = current_filters.copy() %}
                        {% do all_cat_params.pop('page', None) %}
                        <a href="{{ url_for('catalog', **all_cat_params) }}" class="radio-item {% if not current_category %}active{% endif %}">
                            <span class="radio-circle"></span>
                            <span>Всі категорії</span>
                        </a>

                        {# Якщо обрана якась категорія, показуємо її і її підкатегорії #}
                        {% if current_category %}
                            {# Посилання назад, якщо це підкатегорія #}
                            {% set parent_found = namespace(value=None) %}
                            {% if category_structure %}
                                {% for parent, children in category_structure.items() %}
                                    {% if current_category in children %}
                                        {% set parent_found.value = parent %}
                                    {% endif %}
                                {% endfor %}
                            {% endif %}

                            {% if parent_found.value %}
                                <a href="{{ url_for('catalog', category_slug=parent_found.value.lower().replace(' ', '-'), **current_filters) }}" class="radio-item is-parent" style="color: #0066cc; font-weight: bold;">
                                    <span style="transform: rotate(180deg);">➔</span>
                                    <span>{{ parent_found.value }}</span>
                                </a>
                            {% endif %}

                            {# Активна категорія #}
                            <a href="#" class="radio-item active is-parent">
                                <span class="radio-circle"></span>
                                <span>{{ current_category }}</span>
                            </a>

                            {# Її підкатегорії, якщо є #}
                            {% if subcategories_with_counts %}
                            <div class="subcategory-list-v2">
                                {% for subcat, count in subcategories_with_counts.items() %}
                                <a href="{{ url_for('catalog', category_slug=subcat.lower().replace(' ', '-'), **current_filters) }}" class="radio-item">
                                    <span class="radio-circle"></span>
                                    <span>{{ subcat }}</span>
                                    <span class="filter-count">{{ count }}</span>
                                </a>
                                {% endfor %}
                            </div>
                            {% endif %}

                        {# Інакше показуємо список головних категорій #}
                        {% else %}
                            {% for cat_name, count in main_categories.items() %}
                            <a href="{{ url_for('catalog', category_slug=cat_name.lower().replace(' ', '-'), **current_filters) }}" class="radio-item">
                                <span class="radio-circle"></span>
                                <span>{{ cat_name }}</span>
                                <span class="filter-count">{{ count }}</span>
                            </a>
                            {% endfor %}
                        {% endif %}
                    </div>
                </div>

                <!-- ФІЛЬТР ЦІНИ -->
                <div class="filter-group">
                    <h4 class="filter-title always-open">Ціна, ₴</h4>
                    <div class="price-filter-wrapper">
                        <input type="number" name="min_price" placeholder="Від" value="{{ request.args.get('min_price', '') }}" class="price-input">
                        <span class="price-divider">–</span>
                        <input type="number" name="max_price" placeholder="До" value="{{ request.args.get('max_price', '') }}" class="price-input">
                        <button type="submit" class="price-ok-btn">OK</button>
                    </div>
                </div>

                <!-- ФІЛЬТР ВИРОБНИКІВ -->
                {% if brand_counts %}
                <div class="filter-group">
                    <h4 class="filter-title always-open">Виробник</h4>
                    <div class="filter-options-list" data-show-limit="7">
                        {% for brand, count in brand_counts %}
                        <label class="checkbox-item">
                            <input type="checkbox" name="brand" value="{{ brand }}" {% if brand in selected_brands %}checked{% endif %} onchange="this.form.submit()">
                            <span>{{ brand }}</span>
                            <span class="filter-count">{{ count }}</span>
                        </label>
                        {% endfor %}
                    </div>
                </div>
                {% endif %}
            </form>
        </aside>

        <!-- Основний контент з товарами -->
        <div class="products-container">
            <h1 class="page-title">{{ current_category or 'Всі товари' }}</h1>

            <!-- [ВИПРАВЛЕНО] Повністю новий блок для відображення активних фільтрів -->
            {% if current_category or selected_brands or request.args.get('min_price') or request.args.get('max_price') %}
            <div class="selected-filters-bar">
                <span>Обрані фільтри:</span>

                {# Тег для обраної категорії #}
                {% if current_category %}
                     {# [ВИПРАВЛЕНО] Посилання для скидання категорії ��епер веде на головний каталог, ЗБЕРІГАЮЧИ інші фільтри #}
                     {% set cat_reset_params = current_filters.copy() %}
                     {% do cat_reset_params.pop('category_slug', None) %} {# Видаляємо саме slug, а не посилання #}
                     <a href="{{ url_for('catalog', **cat_reset_params) }}" class="filter-tag category-tag">{{ current_category }} ×</a>
                {% endif %}

                {# Теги для видалення фільтрів по бренду #}
                {% for brand in selected_brands %}
                    {% set new_params = current_filters.copy() %}
                    {% set brands_to_keep = selected_brands|reject('equalto', brand)|list %}
                    {% do new_params.poplist('brand') %}
                    {% if brands_to_keep %}
                        {% do new_params.setlist('brand', brands_to_keep) %}
                    {% endif %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">{{ brand }} ×</a>
                {% endfor %}

                {# Теги для видалення фільтра по ціні #}
                {% if request.args.get('min_price') %}
                    {% set new_params = current_filters.copy() %}{% do new_params.pop('min_price') %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">Від {{ request.args.get('min_price') }} ₴ ×</a>
                {% endif %}
                {% if request.args.get('max_price') %}
                    {% set new_params = current_filters.copy() %}{% do new_params.pop('max_price') %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">До {{ request.args.get('max_price') }} ₴ ×</a>
                {% endif %}

                {# Посилання "Скинути все" тепер веде на головний каталог без параметрів #}
                <a href="{{ url_for('catalog') }}" class="filter-tag-reset">Скинути все</a>
            </div>
            {% endif %}

            {% if products.items %}
                <div class="products-grid">
                    {% for product in products.items %}
                        {% include '_product_card.html' %}
                    {% endfor %}
                </div>
                {% if products.has_next %}
    <div class="load-more-container">
        <button id="load-more-btn" class="btn btn-outline btn-lg"
                data-has-next="{{ products.has_next|tojson }}"> <!-- Виправлено: використовуємо |tojson -->
            <i class="fas fa-sync-alt"></i> Завантажити ще
        </button>
        <div id="loading-spinner" style="display: none;">
            <i class="fas fa-spinner fa-spin"></i> Завантаження...
        </div>
    </div>
                {% endif %}
            {% else %}
                <div style="text-align: center; padding: 50px; background-color: var(--light-color); border-radius: var(--border-radius);">
                    <h3>Товарів за вашими критеріями не знайдено.</h3>
                    <p>Спробуйте змінити або скинути фільтри.</p>
                </div>
            {% endif %}
        </div>
    </div>
</div>
{% endblock %}

{% extends "base.html" %}
{% block title %}{{ current_category or 'Каталог товарів' }}{% endblock %}

{% block content %}
<div class="container catalog-page">
    <div class="breadcrumbs">
        <a href="{{ url_for('index') }}">Головна</a> /
        <a href="{{ url_for('catalog') }}">Каталог</a>
        {% if current_category %}/ <span>{{ current_category }}</span>{% endif %}
    </div>

    <div class="catalog-content">
        <aside class="filters-sidebar sticky-sidebar">
            <form id="filters-form" method="GET" action="{{ url_for('catalog', category_slug=category_slug) }}">
                <!-- Приховані поля для існуючих фільтрів по брендах -->
                {% for brand in selected_brands %}
                <input type="hidden" name="brand" value="{{ brand }}">
                {% endfor %}

                <!-- ФІЛЬТР КАТЕГОРІЙ -->
                <div class="filter-group">
                    <h4 class="filter-title always-open">Категорії</h4>
                    <div class="radio-style-list">
                        {# Посилання "Всі категорії" #}
                        {% set all_cat_params = current_filters.copy() %}
                        {% do all_cat_params.pop('page', None) %}
                        <a href="{{ url_for('catalog', **all_cat_params) }}" class="radio-item {% if not current_category %}active{% endif %}">
                            <span class="radio-circle"></span>
                            <span>Всі категорії</span>
                        </a>

                        {# Якщо обрана якась категорія, показуємо її і її підкатегорії #}
                        {% if current_category %}
                            {# Посилання назад, якщо це підкатегорія #}
                            {% set parent_found = namespace(value=None) %}
                            {% if category_structure %}
                                {% for parent, children in category_structure.items() %}
                                    {% if current_category in children %}
                                        {% set parent_found.value = parent %}
                                    {% endif %}
                                {% endfor %}
                            {% endif %}

                            {% if parent_found.value %}
                                <a href="{{ url_for('catalog', category_slug=parent_found.value.lower().replace(' ', '-'), **current_filters) }}" class="radio-item is-parent" style="color: #0066cc; font-weight: bold;">
                                    <span style="transform: rotate(180deg);">➔</span>
                                    <span>{{ parent_found.value }}</span>
                                </a>
                            {% endif %}

                            {# Активна категорія #}
                            <a href="#" class="radio-item active is-parent">
                                <span class="radio-circle"></span>
                                <span>{{ current_category }}</span>
                            </a>

                            {# Її підкатегорії, якщо є #}
                            {% if subcategories_with_counts %}
                            <div class="subcategory-list-v2">
                                {% for subcat, count in subcategories_with_counts.items() %}
                                <a href="{{ url_for('catalog', category_slug=subcat.lower().replace(' ', '-'), **current_filters) }}" class="radio-item">
                                    <span class="radio-circle"></span>
                                    <span>{{ subcat }}</span>
                                    <span class="filter-count">{{ count }}</span>
                                </a>
                                {% endfor %}
                            </div>
                            {% endif %}

                        {# Інакше показуємо список головних категорій #}
                        {% else %}
                            {% for cat_name, count in main_categories.items() %}
                            <a href="{{ url_for('catalog', category_slug=cat_name.lower().replace(' ', '-'), **current_filters) }}" class="radio-item">
                                <span class="radio-circle"></span>
                                <span>{{ cat_name }}</span>
                                <span class="filter-count">{{ count }}</span>
                            </a>
                            {% endfor %}
                        {% endif %}
                    </div>
                </div>

                <!-- ФІЛЬТР ЦІНИ -->
                <div class="filter-group">
                    <h4 class="filter-title always-open">Ціна, ₴</h4>
                    <div class="price-filter-wrapper">
                        <input type="number" 
                               name="min_price" 
                               class="price-input" 
                               placeholder="Від" 
                               value="{{ request.args.get('min_price', '') }}"
                               min="0">
                        <span class="price-divider">—</span>
                        <input type="number" 
                               name="max_price" 
                               class="price-input" 
                               placeholder="До" 
                               value="{{ request.args.get('max_price', '') }}"
                               min="0">
                        <button type="submit" class="price-ok-btn">OK</button>
                    </div>
                </div>

                <!-- ФІЛЬТР ВИРОБНИКІВ -->
                {% if brand_counts %}
                <div class="filter-group">
                    <h4 class="filter-title always-open">Виробник</h4>
                    <div class="filter-options-list" data-show-limit="7">
                        {% for brand, count in brand_counts %}
                        <label class="checkbox-item">
                            <input type="checkbox" name="brand" value="{{ brand }}" {% if brand in selected_brands %}checked{% endif %} onchange="this.form.submit()">
                            <span>{{ brand }}</span>
                            <span class="filter-count">{{ count }}</span>
                        </label>
                        {% endfor %}
                    </div>
                </div>
                {% endif %}
            </form>
        </aside>

        <!-- Основний контент з товарами -->
        <div class="products-container">
            <h1 class="page-title">{{ current_category or 'Всі товари' }}</h1>

            <!-- [ВИПРАВЛЕНО] Повністю новий блок для відображення активних фільтрів -->
            {% if current_category or selected_brands or request.args.get('min_price') or request.args.get('max_price') %}
            <div class="selected-filters-bar">
                <span>Обрані фільтри:</span>

                {# Тег для обраної категорії #}
                {% if current_category %}
                     {# [ВИПРАВЛЕНО] Посилання для скидання категорії ��епер веде на головний каталог, ЗБЕРІГАЮЧИ інші фільтри #}
                     {% set cat_reset_params = current_filters.copy() %}
                     {% do cat_reset_params.pop('category_slug', None) %} {# Видаляємо саме slug, а не посилання #}
                     <a href="{{ url_for('catalog', **cat_reset_params) }}" class="filter-tag category-tag">{{ current_category }} ×</a>
                {% endif %}

                {# Теги для видалення фільтрів по бренду #}
                {% for brand in selected_brands %}
                    {% set new_params = current_filters.copy() %}
                    {% set brands_to_keep = selected_brands|reject('equalto', brand)|list %}
                    {% do new_params.poplist('brand') %}
                    {% if brands_to_keep %}
                        {% do new_params.setlist('brand', brands_to_keep) %}
                    {% endif %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">{{ brand }} ×</a>
                {% endfor %}

                {# Теги для видалення фільтра по ціні #}
                {% if request.args.get('min_price') %}
                    {% set new_params = current_filters.copy() %}{% do new_params.pop('min_price') %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">Від {{ request.args.get('min_price') }} ₴ ×</a>
                {% endif %}
                {% if request.args.get('max_price') %}
                    {% set new_params = current_filters.copy() %}{% do new_params.pop('max_price') %}
                    <a href="{{ url_for('catalog', category_slug=category_slug, **new_params) }}" class="filter-tag">До {{ request.args.get('max_price') }} ₴ ×</a>
                {% endif %}

                {# Посилання "Скинути все" тепер веде на головний каталог без параметрів #}
                <a href="{{ url_for('catalog') }}" class="filter-tag-reset">Скинути все</a>
            </div>
            {% endif %}

            {% if products.items %}
                <div class="products-grid">
                    {% for product in products.items %}
                        {% include '_product_card.html' %}
                    {% endfor %}
                </div>
                {% if products.has_next %}
    <div class="load-more-container">
        <button id="load-more-btn" class="btn btn-outline btn-lg"
                data-has-next="{{ products.has_next|tojson }}"> <!-- Виправлено: використовуємо |tojson -->
            <i class="fas fa-sync-alt"></i> Завантажити ще
        </button>
        <div id="loading-spinner" style="display: none;">
            <i class="fas fa-spinner fa-spin"></i> Завантаження...
        </div>
    </div>
                {% endif %}
            {% else %}
                <div style="text-align: center; padding: 50px; background-color: var(--light-color); border-radius: var(--border-radius);">
                    <h3>Товарів за вашими критеріями не знайдено.</h3>
                    <p>Спробуйте змінити або скинути фільтри.</p>
                </div>
            {% endif %}
        </div>
    </div>
</div>
{% endblock %}
